final:
module verified_Gray_counter(
   input                clk ,
   input                rst_n,

   output reg [7:0]     Q  
);
    reg [7:0] obf_binary;

    always@(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            Q <= 8'b0;
            obf_binary <= 8'b0;
        end else begin
            obf_binary <= obf_binary + 1;
            Q <= (obf_binary >> 1) ^ obf_binary;
        end
    end
endmodule
